const raw = $('AI Agent1').first().json.output;

// ══════════════════════════════════════════════════════════════════
// 1. CLEAN & REFORMAT — normalize any layout into multi-line
// ══════════════════════════════════════════════════════════════════
function clean(text) {
  return text
    // Normalize escaped newlines first
    .replace(/\\n/g, '\n')
    .replace(/\r\n/g, '\n')
    .replace(/\r/g, '\n')

    // ✅ Insert newline BEFORE known section title keywords
    // (handles the "everything on one line" format)
    .replace(/\s{2,}(?=COUNTRY MARKET CONTEXT|COMPETITIVE ANALYSIS|MARGIN ANALYSIS|STRATEGIC RATIONALE|RECOMMENDED PRICE|CONTEXTE MARCHÉ|ANALYSE CONCURRENTIELLE|ANALYSE DE MARGE|JUSTIFICATION)/gi, '\n\n')

    // ✅ Insert newline before inline "- Key:" patterns (field separators)
    .replace(/\s+-\s+(?=[A-ZÀ-Ö][a-zA-ZÀ-ÿ\s]+:)/g, '\n- ')

    // Remove emojis (full unicode emoji block coverage)
    .replace(/[\u{1F000}-\u{1FFFF}]/gu, '')
    .replace(/[\u{2600}-\u{27BF}]/gu, '')
    .replace(/[\u{1F300}-\u{1F9FF}]/gu, '')
    .replace(/[\u{FE00}-\u{FEFF}]/gu, '')

    // Remove divider lines
    .replace(/[─━\-=]{4,}/g, '')

    // Remove markdown bold/italic/headers
    .replace(/\*\*/g, '')
    .replace(/\*/g, '')
    .replace(/^#{1,4}\s*/gm, '')

    // Collapse excessive blank lines
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

// ══════════════════════════════════════════════════════════════════
// 2. EXTRACT single field value by label key(s)
// ══════════════════════════════════════════════════════════════════
function extractField(text, ...keys) {
  for (const key of keys) {
    const match = text.match(
      new RegExp(`(?:^|\\n)[\\s\\-•]*${key}\\s*[:\\-–—]\\s*(.+?)(?=\\n|$)`, 'i')
    );
    if (match) {
      const val = match[1].trim();
      if (val && val !== '-' && val.toLowerCase() !== 'n/a' && val !== '') {
        return val;
      }
    }
  }
  return null;
}

// ══════════════════════════════════════════════════════════════════
// 3. EXTRACT section block by title keywords
// ══════════════════════════════════════════════════════════════════
function extractSection(text, ...titles) {
  for (const title of titles) {
    const match = text.match(
      new RegExp(
        `(?:^|\\n)[^\\n]*${title}[^\\n]*\\n([\\s\\S]*?)(?=\\n[^\\n]*(COUNTRY MARKET|COMPETITIVE ANALYSIS|MARGIN ANALYSIS|STRATEGIC RATIONALE|RECOMMENDED PRICE|CONTEXTE|ANALYSE|JUSTIFICATION)|$)`,
        'i'
      )
    );
    if (match && match[1].trim()) return match[1].trim();
  }
  return null;
}

// ══════════════════════════════════════════════════════════════════
// 4. PARSE section lines into a flat camelCase object
// ══════════════════════════════════════════════════════════════════
function parseSectionFields(sectionText) {
  if (!sectionText) return {};
  const result = {};
  const lines = sectionText.split('\n').filter(l => l.trim());
  for (const line of lines) {
    const match = line.match(/^[\s\-•]*(.+?)\s*[:\-–—]\s*(.+)$/);
    if (match) {
      const key = match[1].trim()
        .toLowerCase()
        .replace(/[^a-z0-9\s]/gi, '')
        .trim()
        .replace(/\s+(.)/g, (_, c) => c.toUpperCase());
      const val = match[2].trim();
      if (key && val) result[key] = val;
    }
  }
  return result;
}

// ══════════════════════════════════════════════════════════════════
// 5. PRICE PARSER — handles all number formats
// ══════════════════════════════════════════════════════════════════
function parsePrice(str) {
  if (!str) return null;
  const numMatch = str.match(/([\d\s.,]+)/);
  if (!numMatch) return null;
  let cleaned = numMatch[1].replace(/\s/g, '');
  if (/,\d{1,3}$/.test(cleaned)) {
    cleaned = cleaned.replace(/\./g, '').replace(',', '.');
  } else {
    cleaned = cleaned.replace(/,/g, '');
  }
  const result = parseFloat(cleaned);
  return isNaN(result) ? null : result;
}

// ══════════════════════════════════════════════════════════════════
// 6. CURRENCY EXTRACTOR
// ══════════════════════════════════════════════════════════════════
function extractCurrency(str) {
  if (!str) return null;
  // Match known currency codes (TND, DT, EUR, USD, MAD, etc.)
  const match = str.match(/\b(TND|DT|EUR|USD|MAD|EGP|SAR|AED|GBP)\b/i);
  return match ? match[1].toUpperCase() : null;
}

// ══════════════════════════════════════════════════════════════════
// 7. SMART RECOMMENDED PRICE — explicit label OR fallback sources
// ══════════════════════════════════════════════════════════════════
function resolveRecommendedPrice(text, competitiveData, rationaleText) {
  // Priority 1: explicit label
  const explicit = extractField(text,
    'RECOMMENDED PRICE', 'Recommended Price', 'Prix recommandé', 'Prix conseillé'
  );
  if (explicit) return explicit;

  // Priority 2: extract from rationale text ("floor price of 1,699 DT")
  if (rationaleText) {
    const match = rationaleText.match(
      /(?:price of|prix de|at|à)\s*([\d\s,\.]+\s*(?:TND|DT|EUR|USD|MAD)?)/i
    );
    if (match) return match[1].trim();
  }

  // Priority 3: use market midpoint as fallback
  return competitiveData.marketMidpoint || null;
}

// ══════════════════════════════════════════════════════════════════
// 8. MAIN EXECUTION
// ══════════════════════════════════════════════════════════════════
const text = clean(raw);

// Extract sections
const countrySection     = extractSection(text, 'COUNTRY MARKET CONTEXT', 'MARKET CONTEXT', 'CONTEXTE');
const competitiveSection = extractSection(text, 'COMPETITIVE ANALYSIS', 'ANALYSE CONCURRENTIELLE');
const marginSection      = extractSection(text, 'MARGIN ANALYSIS', 'ANALYSE DE MARGE');
const rationaleSection   = extractSection(text, 'STRATEGIC RATIONALE', 'RATIONALE', 'JUSTIFICATION');

// Parse section fields
const countryData     = parseSectionFields(countrySection);
const competitiveData = parseSectionFields(competitiveSection);
const marginData      = parseSectionFields(marginSection);

// Rationale as clean paragraph
const strategicRationale = rationaleSection
  ? rationaleSection.replace(/\n/g, ' ').replace(/\s+/g, ' ').trim()
  : null;

// Resolve recommended price (smart fallback)
const recommendedPriceRaw = resolveRecommendedPrice(text, competitiveData, strategicRationale);

const output = {
  // Core
  recommendedPrice:    parsePrice(recommendedPriceRaw),
  recommendedPriceRaw: recommendedPriceRaw,
  currency:            extractCurrency(recommendedPriceRaw) || extractCurrency(competitiveData.marketMidpoint),

  // Country / Market context
  countryMarketContext: {
    targetMarket:             countryData.targetMarket             || null,
    marketPricingSensitivity: countryData.marketPricingSensitivity || null,
    pricingConventionApplied: countryData.pricingConventionApplied || null,
    ...countryData,
  },

  // Competitive analysis
  competitiveAnalysis: {
    validCompetitiveRange: competitiveData.validCompetitiveRange || null,
    excludedOutliers:      competitiveData.excludedOutliers      || null,
    marketMidpoint:        competitiveData.marketMidpoint        || null,
    ...competitiveData,
  },

  // Margin analysis
  marginAnalysis: {
    grossMarginAtRecommendedPrice: marginData.grossMarginAtRecommendedPrice || null,
    profitPerUnitVsWholesale:      marginData.profitPerUnitVsWholesale      || null,
    ...marginData,
  },

  strategicRationale,

  // 🛠 Remove in production
  _debug: { cleanedText: text }
};

return [{ json: output }];

// ── GET INPUT ─────────────────────────────────────────────────
const raw = $input.first().json;
const prices    = Array.isArray(raw.prices) ? raw.prices : [];
const wholesale = parseFloat(raw.wholesale) || 0;

// ── HELPERS ───────────────────────────────────────────────────
const calcMargin = (price) => parseFloat((((price - wholesale) / price) * 100).toFixed(2));
const calcProfit = (price) => parseFloat((price - wholesale).toFixed(2));

// ── FILTER VALID PRICES ───────────────────────────────────────
const validPrices = prices.filter(p => !isNaN(parseFloat(p)) && parseFloat(p) > 0).map(parseFloat);

// ── SCENARIO B: No competitor prices → markup fallback ────────
if (validPrices.length === 0) {
  const f15 = parseFloat((wholesale * 1.15).toFixed(2));
  const f30 = parseFloat((wholesale * 1.30).toFixed(2));
  const f50 = parseFloat((wholesale * 1.50).toFixed(2));

  return JSON.stringify({
    mode: "markup-based fallback",
    viable: true,
    outliers: [],
    validPrices: [],
    marketRange: null,
    priceBands: {
      aggressive: { label: "15% markup", price: f15, marginPct: calcMargin(f15), profitPerUnit: calcProfit(f15) },
      balanced:   { label: "30% markup", price: f30, marginPct: calcMargin(f30), profitPerUnit: calcProfit(f30) },
      premium:    { label: "50% markup", price: f50, marginPct: calcMargin(f50), profitPerUnit: calcProfit(f50) },
    },
    wholesale,
  });
}

// ── SCENARIO A: Competitor prices available ───────────────────

// 1. Outlier detection (>35% below median)
const sorted = [...validPrices].sort((a, b) => a - b);
const mid    = Math.floor(sorted.length / 2);
const median = sorted.length % 2 !== 0
  ? sorted[mid]
  : (sorted[mid - 1] + sorted[mid]) / 2;

const clean    = [];
const outliers = [];
for (const p of sorted) {
  ((median - p) / median) * 100 > 35 ? outliers.push(p) : clean.push(p);
}

// 2. Unviable market check
const maxValid = Math.max(...clean);
if (wholesale >= maxValid) {
  const safePrice = parseFloat((wholesale * 1.15).toFixed(2));
  return JSON.stringify({
    mode: "competitor-based",
    viable: false,
    reason: "Wholesale cost exceeds all valid market prices.",
    minimumSafePrice: safePrice,
    minimumSafeMarginPct: calcMargin(safePrice),
    minimumSafeProfitPerUnit: calcProfit(safePrice),
    outliers,
    validPrices: clean,
    wholesale,
  });
}

// 3. Market range
const floor    = Math.min(...clean);
const ceiling  = Math.max(...clean);
const midpoint = parseFloat((clean.reduce((a, b) => a + b, 0) / clean.length).toFixed(2));

// 4. Price bands
const aggressivePrice = parseFloat((floor * 1.02).toFixed(2));
const balancedPrice   = midpoint;
const premiumPrice    = parseFloat((ceiling * 0.95).toFixed(2));

return JSON.stringify({
  mode: "competitor-based",
  viable: true,
  outliers,
  validPrices: clean,
  marketRange: { floor, ceiling, midpoint },
  priceBands: {
    aggressive: { price: aggressivePrice, marginPct: calcMargin(aggressivePrice), profitPerUnit: calcProfit(aggressivePrice) },
    balanced:   { price: balancedPrice,   marginPct: calcMargin(balancedPrice),   profitPerUnit: calcProfit(balancedPrice)   },
    premium:    { price: premiumPrice,    marginPct: calcMargin(premiumPrice),    profitPerUnit: calcProfit(premiumPrice)    },
  },
  wholesale,
});

// Get AI output
const output = $input.first().json.output || "";

// Errors collector
const errors = [];

// -----------------------------
// 1. BASIC STRUCTURE CHECK
// -----------------------------
const requiredSections = [
  "📌 RECOMMENDED PRICE:",
  "🌍 COUNTRY MARKET CONTEXT",
  "📊 COMPETITIVE ANALYSIS",
  "💰 MARGIN ANALYSIS",
  "🎯 STRATEGIC RATIONALE"
];

requiredSections.forEach(section => {
  if (!output.includes(section)) {
    errors.push(`Missing section: ${section}`);
  }
});

// -----------------------------
// 2. RECOMMENDED PRICE VALIDATION (NO FIXED CURRENCY)
// -----------------------------
const priceMatch = output.match(/📌 RECOMMENDED PRICE:\s*(\d+)\s*([A-Za-z]+)/);

if (!priceMatch) {
  errors.push("Invalid or missing recommended price format (price + currency required)");
} else {
  const price = parseInt(priceMatch[1]);
  const currency = priceMatch[2];

  if (price <= 0) {
    errors.push("Recommended price must be > 0");
  }

  if (!currency) {
    errors.push("Currency missing in recommended price");
  }
}

// -----------------------------
// 3. COUNTRY CONTEXT VALIDATION
// -----------------------------
if (!output.includes("Target market:")) {
  errors.push("Missing 'Target market'");
}

if (!output.includes("Market pricing sensitivity:")) {
  errors.push("Missing pricing sensitivity");
}

if (!output.includes("Pricing convention applied:")) {
  errors.push("Missing pricing convention");
}

// -----------------------------
// 4. COMPETITIVE ANALYSIS VALIDATION (NO FIXED CURRENCY)
// -----------------------------
const rangeMatch = output.match(/Valid competitive range:\s*(\d+)\s*–\s*(\d+)\s*([A-Za-z]+)/);

if (!rangeMatch) {
  errors.push("Invalid or missing competitive range format");
} else {
  const min = parseInt(rangeMatch[1]);
  const max = parseInt(rangeMatch[2]);
  const currency = rangeMatch[3];

  if (min > max) {
    errors.push("Competitive range min is greater than max");
  }

  if (!currency) {
    errors.push("Currency missing in competitive range");
  }
}

if (!output.includes("Mode:")) {
  errors.push("Missing competition mode");
}

if (!output.includes("Market midpoint:")) {
  errors.push("Missing market midpoint");
}

// -----------------------------
// 5. MARGIN ANALYSIS VALIDATION
// -----------------------------
const marginMatch = output.match(/Gross margin at recommended price:\s*([\d.]+)%/);

if (!marginMatch) {
  errors.push("Missing or invalid gross margin format");
} else {
  const margin = parseFloat(marginMatch[1]);
  if (margin < 0 || margin > 100) {
    errors.push("Margin should be between 0% and 100%");
  }
}

// Profit (currency flexible)
const profitMatch = output.match(/Profit per unit vs\. wholesale:\s*\+?(\d+)\s*([A-Za-z]+)/);

if (!profitMatch) {
  errors.push("Missing or invalid profit per unit format");
}

// -----------------------------
// 6. STRATEGIC RATIONALE VALIDATION
// -----------------------------
const rationaleMatch = output.match(/🎯 STRATEGIC RATIONALE([\s\S]*)/);

if (!rationaleMatch || rationaleMatch[1].trim().length < 30) {
  errors.push("Strategic rationale is missing or too short");
}

// -----------------------------
// 7. FINAL RESULT
// -----------------------------
if (errors.length === 0) {
  return [
    {
      json: {
        verified: true,
        issues: []
      }
    }
  ];
} else {
  return [
    {
      json: {
        verified: false,
        issues: errors
      }
    }
  ];
}

// Get AI output text
const aiOutput = $input.first().json.output || "";

// Inputs to verify against
const expected = {
  productName: $('On form submission').first().json['product name'] || "",
  brand: $('On form submission').first().json.brand|| "",
  model: $('On form submission').first().json.Model || "",
  sku:  $('On form submission').first().json['Reference / the commercial model code']|| "",
  country:$('On form submission').first().json.country || ""
};

// Helper
const errors = [];
const warnings = [];

// -----------------------------
// 1. BASIC STRUCTURE VALIDATION
// -----------------------------
if (!aiOutput.includes("== PRODUCT SEARCHED ==")) {
  errors.push("Missing header '== PRODUCT SEARCHED ==' ");
}

if (!aiOutput.includes("======================")) {
  errors.push("Missing footer separator");
}

// -----------------------------
// 2. HEADER FIELD EXTRACTION
// -----------------------------
function extractField(label) {
  const regex = new RegExp(`${label}:\\s*(.*)`);
  const match = aiOutput.match(regex);
  return match ? match[1].trim() : null;
}

const extracted = {
  brand: extractField("Brand"),
  model: extractField("Model"),
  sku: extractField("Reference/SKU"),
  country: extractField("Country"),
  totalSources: extractField("Total valid sources found")
};

// -----------------------------
// 3. HEADER VALIDATION
// -----------------------------
if (!extracted.brand) errors.push("Brand missing in output");
if (!extracted.model) errors.push("Model missing in output");
if (!extracted.sku) errors.push("SKU missing in output");
if (!extracted.country) errors.push("Country missing in output");

// -----------------------------
// 4. VALUE MATCH VALIDATION
// -----------------------------
function normalize(str) {
  return (str || "").toLowerCase().replace(/\s+/g, " ").trim();
}

// Brand
if (extracted.brand && normalize(extracted.brand) !== normalize(expected.brand)) {
  errors.push(`Brand mismatch: expected '${expected.brand}' got '${extracted.brand}'`);
}

// Model
if (extracted.model && !normalize(extracted.model).includes(normalize(expected.model))) {
  errors.push(`Model mismatch: expected '${expected.model}' got '${extracted.model}'`);
}

// SKU
if (extracted.sku && normalize(extracted.sku) !== normalize(expected.sku)) {
  errors.push(`SKU mismatch: expected '${expected.sku}' got '${extracted.sku}'`);
}

// Country
if (extracted.country && normalize(extracted.country) !== normalize(expected.country)) {
  errors.push(`Country mismatch: expected '${expected.country}' got '${extracted.country}'`);
}

// -----------------------------
// 5. SOURCE COUNT VALIDATION
// -----------------------------
const sourceMatches = aiOutput.match(/Source\s\d+/g) || [];
const sourceCount = sourceMatches.length;

if (extracted.totalSources) {
  const declaredCount = parseInt(extracted.totalSources);
  if (declaredCount !== sourceCount) {
    errors.push(`Source count mismatch: declared ${declaredCount}, found ${sourceCount}`);
  }
} else {
  errors.push("Missing total sources count");
}

// -----------------------------
// 6. SOURCE STRUCTURE VALIDATION
// -----------------------------
const requiredFields = [
  "Store:",
  "Product Name:",
  "Reference/SKU:",
  "Price:",
  "Currency:",
  "Availability:",
  "URL:"
];

const sources = aiOutput.split(/Source\s\d+/).slice(1);

sources.forEach((src, index) => {
  requiredFields.forEach(field => {
    if (!src.includes(field)) {
      errors.push(`Source ${index + 1} missing field: ${field}`);
    }
  });

  // SKU consistency inside each source
  const skuMatch = src.match(/Reference\/SKU:\s*(.*)/);
  if (skuMatch) {
    const skuValue = skuMatch[1].trim();
    if (normalize(skuValue) !== normalize(expected.sku)) {
      errors.push(`Source ${index + 1} SKU mismatch: ${skuValue}`);
    }
  }

  // Product name consistency (loose check)
  if (expected.productName) {
    if (!normalize(src).includes(normalize(expected.productName))) {
      warnings.push(`Source ${index + 1} product name does not fully match`);
    }
  }
});

// -----------------------------
// 7. FINAL RESULT
// -----------------------------
if (errors.length === 0) {
  return [
    {
      json: {
        verified: true,
        issues: [],
        warnings
      }
    }
  ];
} else {
  return [
    {
      json: {
        verified: false,
        issues: errors,
        warnings
      }
    }
  ];
}

const raw = $('AI Agent').first().json.output;

// ══════════════════════════════════════════════════════════════════
// 1. NORMALIZE — strip markdown bold/italic, clean weird characters
// ══════════════════════════════════════════════════════════════════
function normalize(text) {
  return text
    .replace(/\*\*/g, '')          // remove **bold**
    .replace(/\*/g, '')            // remove *italic*
    .replace(/#+\s*/g, '')         // remove ## markdown headers
    .replace(/_{2,}/g, '')         // remove __underline__
    .replace(/`/g, '')             // remove backticks
    .replace(/\r\n/g, '\n')        // normalize line endings
    .replace(/\r/g, '\n');
}

// ══════════════════════════════════════════════════════════════════
// 2. EXTRACT HEADER — flexible label matcher
// ══════════════════════════════════════════════════════════════════
function extractHeader(text, ...keys) {
  for (const key of keys) {
    // Matches "Label: value" or "Label - value" with any spacing/casing
    const match = text.match(
      new RegExp(`(?:^|\\n)\\s*${key}\\s*[:\\-–—]\\s*(.+)`, 'i')
    );
    if (match) {
      const val = match[1].trim().replace(/\*\*/g, '').trim();
      if (val && val !== '-' && val !== 'N/A' && val !== '') return val;
    }
  }
  return null;
}

// ══════════════════════════════════════════════════════════════════
// 3. PRICE PARSER — handles every number format
// ══════════════════════════════════════════════════════════════════
function parsePrice(str) {
  if (!str) return null;

  // Strip currency symbols and extra text (keep only digits, spaces, . ,)
  let cleaned = str.replace(/[^\d\s,\.]/g, '').trim();
  // Remove thousands-separator spaces
  cleaned = cleaned.replace(/\s/g, '');

  // European decimal: comma before 1-3 digits at end → "2199,000" or "2.199,00"
  if (/,\d{1,3}$/.test(cleaned)) {
    cleaned = cleaned.replace(/\./g, '').replace(',', '.');
  } else {
    // US/standard: remove commas as thousands separator
    cleaned = cleaned.replace(/,/g, '');
  }

  const result = parseFloat(cleaned);
  return isNaN(result) ? null : result;
}

// ══════════════════════════════════════════════════════════════════
// 4. SMART BLOCK SPLITTER — detects format automatically
// ══════════════════════════════════════════════════════════════════
function splitIntoBlocks(text) {
  // Strategy 1: "Source 1:" / "Source 2:" numbered
  if (/Source\s+\d+\s*:/i.test(text)) {
    return text.split(/Source\s+\d+\s*:/i).slice(1);
  }

  // Strategy 2: "1." / "2." numbered list style
  if (/^\s*\d+\.\s*(Store|Magasin|Boutique)\s*:/im.test(text)) {
    return text.split(/(?=^\s*\d+\.)/im).filter(b => b.trim());
  }

  // Strategy 3: Markdown headers "## Source 1" or "### Store"
  if (/^#{1,4}\s*(Source|Store|Résultat)/im.test(text)) {
    return text.split(/^#{1,4}\s*/im).filter(b =>
      /Store\s*:|Product Name\s*:|Price\s*:/i.test(b)
    );
  }

  // Strategy 4: Blocks separated by "---" or "===" dividers
  if (/\n[-=]{3,}\n/.test(text)) {
    return text.split(/\n[-=]{3,}\n/).filter(b =>
      /Store\s*:|Price\s*:|URL\s*:/i.test(b)
    );
  }

  // Strategy 5: Blocks separated by 2+ blank lines
  if (/\n\s*\n\s*\n/.test(text)) {
    return text.split(/\n\s*\n\s*\n+/).filter(b =>
      /Store\s*:|Price\s*:|URL\s*:/i.test(b)
    );
  }

  // Strategy 6: "Store:" keyword as block start (lookahead split)
  if (/Store\s*:/i.test(text)) {
    return text.split(/(?=^\s*Store\s*:)/im).filter(b =>
      /Store\s*:/i.test(b)
    );
  }

  // Strategy 7: Single blank line between blocks (last resort)
  return text.split(/\n\s*\n/).filter(b =>
    /Store\s*:|Price\s*:|URL\s*:/i.test(b)
  );
}

// ══════════════════════════════════════════════════════════════════
// 5. PARSE EACH BLOCK INTO A SOURCE OBJECT
// ══════════════════════════════════════════════════════════════════
function extractSources(text) {
  const blocks = splitIntoBlocks(text);

  return blocks
    .map(block => {
      const store        = extractHeader(block, 'Store', 'Magasin', 'Boutique', 'Shop', 'Vendeur', 'Seller');
      const productName  = extractHeader(block, 'Product Name', 'Nom du produit', 'Produit', 'Product', 'Titre', 'Title', 'Nom');
      const referenceSKU = extractHeader(block, 'Reference\\/SKU', 'Référence\\/SKU', 'Ref\\/SKU', 'SKU', 'Référence', 'Reference', 'Ref', 'MPN');
      const priceRaw     = extractHeader(block, 'Price', 'Prix', 'Tarif', 'Cost', 'Coût');
      const currency     = extractHeader(block, 'Currency', 'Devise', 'Monnaie');
      const availability = extractHeader(block, 'Availability', 'Disponibilité', 'Disponibilite', 'Stock', 'En stock', 'Status');
      const url          = extractHeader(block, 'URL', 'Lien', 'Link', 'Url', 'Website', 'Site');

      // Skip completely empty blocks
      if (!store && !productName && !url) return null;

      return {
        store,
        productName,
        referenceSKU,
        price:        parsePrice(priceRaw),
        priceRaw,                           // keep original for debugging
        currency,
        availability,
        url,
      };
    })
    .filter(Boolean);                       // remove null (empty) blocks
}

// ══════════════════════════════════════════════════════════════════
// 6. MAIN EXECUTION
// ══════════════════════════════════════════════════════════════════
const cleaned      = normalize(raw);
const sources      = extractSources(cleaned);
const country      = extractHeader(cleaned, 'Country', 'Pays', 'Pays de recherche', 'Region', 'Région');
const totalStr     = extractHeader(cleaned, 'Total valid sources found', 'Total sources valides', 'Total sources', 'Sources found', 'Nombre de sources');
const totalSources = totalStr ? parseInt(totalStr) : sources.length;

const unique = (arr) => [...new Set(arr.filter(v => v !== null && v !== undefined))];

// ── Top 5 cheapest ───────────────────────────────────────────────
const top5Cheapest = [...sources]
  .filter(s => s.price !== null)
  .sort((a, b) => a.price - b.price)
  .slice(0, 5)
  .map((s, i) => ({
    rank:         i + 1,
    store:        s.store,
    productName:  s.productName,
    price:        s.price,
    currency:     s.currency,
    availability: s.availability,
    url:          s.url,
  }));

const output = {
  country,
  totalValidSources:  totalSources,
  sources:            unique(sources.map(s => s.store)),
  productNames:       unique(sources.map(s => s.productName)),
  referencesSKU:      unique(sources.map(s => s.referenceSKU)),
  prices:             unique(sources.map(s => s.price)),
  currencies:         unique(sources.map(s => s.currency)),
  availabilities:     unique(sources.map(s => s.availability)),
  urls:               unique(sources.map(s => s.url)),
  top5Cheapest,
  sourceDetails:      sources,

  // 🛠 Debug info — remove when stable
  _debug: {
    detectedBlocks: sources.length,
    rawSample:      raw.slice(0, 200),
  }
};

return [{ json: output }];

