parameters.jsCode:
// ── GET INPUT ─────────────────────────────────────────────────
const raw = $input.first().json;
const prices    = Array.isArray(raw.prices) ? raw.prices : [];
const wholesale = parseFloat(raw.wholesale) || 0;

// ── HELPERS ───────────────────────────────────────────────────
const calcMargin = (price) => parseFloat((((price - wholesale) / price) * 100).toFixed(2));
const calcProfit = (price) => parseFloat((price - wholesale).toFixed(2));

// ── FILTER VALID PRICES ───────────────────────────────────────
const validPrices = prices.filter(p => !isNaN(parseFloat(p)) && parseFloat(p) > 0).map(parseFloat);

// ── SCENARIO B: No competitor prices → markup fallback ────────
if (validPrices.length === 0) {
  const f15 = parseFloat((wholesale * 1.15).toFixed(2));
  const f30 = parseFloat((wholesale * 1.30).toFixed(2));
  const f50 = parseFloat((wholesale * 1.50).toFixed(2));

  return JSON.stringify({
    mode: "markup-based fallback",
    viable: true,
    outliers: [],
    validPrices: [],
    marketRange: null,
    priceBands: {
      aggressive: { label: "15% markup", price: f15, marginPct: calcMargin(f15), profitPerUnit: calcProfit(f15) },
      balanced:   { label: "30% markup", price: f30, marginPct: calcMargin(f30), profitPerUnit: calcProfit(f30) },
      premium:    { label: "50% markup", price: f50, marginPct: calcMargin(f50), profitPerUnit: calcProfit(f50) },
    },
    wholesale,
  });
}

// ── SCENARIO A: Competitor prices available ───────────────────

// 1. Outlier detection (>35% below median)
const sorted = [...validPrices].sort((a, b) => a - b);
const mid    = Math.floor(sorted.length / 2);
const median = sorted.length % 2 !== 0
  ? sorted[mid]
  : (sorted[mid - 1] + sorted[mid]) / 2;

const clean    = [];
const outliers = [];
for (const p of sorted) {
  ((median - p) / median) * 100 > 35 ? outliers.push(p) : clean.push(p);
}

// 2. Unviable market check
const maxValid = Math.max(...clean);
if (wholesale >= maxValid) {
  const safePrice = parseFloat((wholesale * 1.15).toFixed(2));
  return JSON.stringify({
    mode: "competitor-based",
    viable: false,
    reason: "Wholesale cost exceeds all valid market prices.",
    minimumSafePrice: safePrice,
    minimumSafeMarginPct: calcMargin(safePrice),
    minimumSafeProfitPerUnit: calcProfit(safePrice),
    outliers,
    validPrices: clean,
    wholesale,
  });
}

// 3. Market range
const floor    = Math.min(...clean);
const ceiling  = Math.max(...clean);
const midpoint = parseFloat((clean.reduce((a, b) => a + b, 0) / clean.length).toFixed(2));

// 4. Price bands
const aggressivePrice = parseFloat((floor * 1.02).toFixed(2));
const balancedPrice   = midpoint;
const premiumPrice    = parseFloat((ceiling * 0.95).toFixed(2));

return JSON.stringify({
  mode: "competitor-based",
  viable: true,
  outliers,
  validPrices: clean,
  marketRange: { floor, ceiling, midpoint },
  priceBands: {
    aggressive: { price: aggressivePrice, marginPct: calcMargin(aggressivePrice), profitPerUnit: calcProfit(aggressivePrice) },
    balanced:   { price: balancedPrice,   marginPct: calcMargin(balancedPrice),   profitPerUnit: calcProfit(balancedPrice)   },
    premium:    { price: premiumPrice,    marginPct: calcMargin(premiumPrice),    profitPerUnit: calcProfit(premiumPrice)    },
  },
  wholesale,
});

