// ══════════════════════════════════════════════════════════════════
// 6. CURRENCY EXTRACTOR
// ══════════════════════════════════════════════════════════════════
function extractCurrency(str) {
  if (!str) return null;
  // Match known currency codes (TND, DT, EUR, USD, MAD, etc.)
  const match = str.match(/\b(TND|DT|EUR|USD|MAD|EGP|SAR|AED|GBP)\b/i);
